SELECT file.*,
DATE(${orderKeyword}) AS group_date,
video_meta_data.duration AS duration
FROM file
INNER JOIN user_file uf on file.file_id = uf.file_id

    INNER JOIN album_picture ap
        ON file.file_id = ap.file_id
       AND ap.album_id = #{albumId}
       AND ap.user_id = #{userId}


    INNER JOIN location l on file.file_id = l.file_id

LEFT JOIN video_meta_data ON file.file_id = video_meta_data.file_id



    uf.is_deleted = #{isDeleted}
    AND uf.user_id = #{userId}




                AND l.country = #{locationValue}


                AND l.province = #{locationValue}


                AND l.city = #{locationValue}


                AND l.district = #{locationValue}







        AND NOT EXISTS (
            SELECT 1
            FROM picture_tag pt
            WHERE pt.file_id = file.file_id
        )



            AND file.category = 'image'
            AND file.content_type != 'image/gif'


            AND file.content_type = 'image/gif'


            AND file.category = 'video'




GROUP BY uf.user_id, file.file_id, group_date
ORDER BY ${orderKeyword}


        ${orderType}


        DESC

